
const PDF_B64="";
// CURSOR
const cur=document.getElementById("cur"),curl=document.getElementById("curl");
let mx=0,my=0,lx=0,ly=0;
document.addEventListener("mousemove",e=>{mx=e.clientX;my=e.clientY;cur.style.left=mx+"px";cur.style.top=my+"px";});
(function al(){lx+=(mx-lx)*.11;ly+=(my-ly)*.11;curl.style.left=lx+"px";curl.style.top=ly+"px";requestAnimationFrame(al);})();
document.querySelectorAll("a,button,.scard,.pcard,.citem,.acard").forEach(el=>{
  el.addEventListener("mouseenter",()=>{cur.style.transform="translate(-50%,-50%) scale(3)";cur.style.opacity=".6";curl.style.width="50px";curl.style.height="50px";curl.style.borderColor="rgba(0,200,248,.7)";});
  el.addEventListener("mouseleave",()=>{cur.style.transform="translate(-50%,-50%) scale(1)";cur.style.opacity="1";curl.style.width="34px";curl.style.height="34px";curl.style.borderColor="rgba(0,200,248,.45)";});
});
// PARTICLES
const cv=document.getElementById("cvs"),x=cv.getContext("2d");
let W=window.innerWidth,H=window.innerHeight;
cv.width=W;cv.height=H;
window.addEventListener("resize",()=>{W=window.innerWidth;H=window.innerHeight;cv.width=W;cv.height=H;});
const pts=Array.from({length:75},()=>({x:Math.random()*W,y:Math.random()*H,vx:(Math.random()-.5)*.22,vy:(Math.random()-.5)*.22,r:Math.random()*1.1+.3,o:Math.random()*.3+.07}));
(function draw(){x.clearRect(0,0,W,H);pts.forEach(p=>{p.x+=p.vx;p.y+=p.vy;if(p.x<0)p.x=W;if(p.x>W)p.x=0;if(p.y<0)p.y=H;if(p.y>H)p.y=0;x.beginPath();x.arc(p.x,p.y,p.r,0,Math.PI*2);x.fillStyle=`rgba(0,200,248,${p.o})`;x.fill();});pts.forEach((a,i)=>pts.slice(i+1).forEach(b=>{const dx=a.x-b.x,dy=a.y-b.y,d=Math.sqrt(dx*dx+dy*dy);if(d<115){x.beginPath();x.moveTo(a.x,a.y);x.lineTo(b.x,b.y);x.strokeStyle=`rgba(0,200,248,${.07*(1-d/115)})`;x.lineWidth=.5;x.stroke();}}));requestAnimationFrame(draw);})();
// NAV
window.addEventListener("scroll",()=>document.getElementById("nav").classList.toggle("scrolled",scrollY>60));
// TYPING
const roles=["WordPress Developer","Full-Stack Developer","MERN Stack Dev","React Developer","Web Developer"];
let ri=0,ci=0,del=false;
const tel=document.getElementById("typed");
function type(){const w=roles[ri];if(!del){tel.textContent=w.slice(0,++ci);if(ci===w.length){del=true;setTimeout(type,1800);return;}}else{tel.textContent=w.slice(0,--ci);if(ci===0){del=false;ri=(ri+1)%roles.length;}}setTimeout(type,del?50:80);}
type();
// REVEAL + BARS
const obs=new IntersectionObserver(entries=>{entries.forEach(e=>{if(e.isIntersecting){e.target.classList.add("on");e.target.querySelectorAll(".bfill").forEach(b=>setTimeout(()=>{b.style.width=b.dataset.w+"%";},300));}});},{threshold:.09});
document.querySelectorAll(".rv").forEach(el=>obs.observe(el));
// PDF DOWNLOAD
function dlPDF(){
  const bytes=atob(PDF_B64);
  const ab=new ArrayBuffer(bytes.length);
  const ia=new Uint8Array(ab);
  for(let i=0;i<bytes.length;i++)ia[i]=bytes.charCodeAt(i);
  const blob=new Blob([ab],{type:"application/pdf"});
  const url=URL.createObjectURL(blob);
  const a=document.createElement("a");
  a.href=url;a.download="Fahad_Ahmed_CV.pdf";a.click();
  URL.revokeObjectURL(url);
}

